          X, /*ForSigned=*/false, SQ.getWithInstruction(&Cmp));
      if (CR.getLower().isZero() && CR.getUpper().ule(M << 1)) {
        APInt NewMask = M >> 1;  // M/2
        Value *NewAnd = Builder.CreateAnd(X, ConstantInt::get(X->getType(), NewMask));
        return new ICmpInst(ICmpInst::ICMP_NE, NewAnd,
